package assignments.java_practice.ifelseassg;

public class marks {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		int a = 50;
		int b = 49;

		if (a % 2 == 1) {
			if (b % 2 == 1) {
				System.out.println("both are odd number : " + (a - b));
			}

		}
		else {
			System.out.println("invalid");
		}

	}
}
